"use server";

import { getProductDatabase } from "../../database/product";

type MongoDocument = Record<string, unknown>;

function serializeDocument<T>(document: T): T {
	return JSON.parse(JSON.stringify(document)) as T;
}

export async function getDashboardProducts() {
	const db = await getProductDatabase();
	const products = await db.collection<MongoDocument>("products").find({}).sort({ createdAt: -1 }).toArray();
	return products.map(serializeDocument);
}

export async function getDashboardCategories() {
	const db = await getProductDatabase();
	const categories = await db.collection<MongoDocument>("categories").find({}).sort({ category: 1 }).toArray();
	return categories.map(serializeDocument);
}

export async function getDashboardBrands() {
	const db = await getProductDatabase();
	const brands = await db.collection<MongoDocument>("item_brands").find({}).sort({ item_brand: 1 }).toArray();
	return brands.map(serializeDocument);
}